    // 1. Create observer nodes
    auto nodeA = std::make_shared<TestTransactionalObserver>("NodeA");
    auto nodeB = std::make_shared<TestTransactionalObserver>("NodeB");
    auto nodeC = std::make_shared<TestTransactionalObserver>("NodeC");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship (A -> B -> C)
    graph.addDependency(nodeA.get(), nodeB.get());
    graph.addDependency(nodeB.get(), nodeC.get());

    // 4. Notify target and verify relationship works
    nodeA->valueChanged();
    bool initialRelationshipWorks = (nodeC->getCallCount() == 1);

    if (!initialRelationshipWorks) {
        return false; // Initial setup failed
    }

    // 5. Reset observer for next test
    nodeA->reset();
    nodeB->reset();
    nodeC->reset();

    // 6. Attempt transactional update that would create cycle
    bool cycleDetected = false;

    // Start a transaction
    graph.beginTransaction();

    try {
        // Try to create a cycle: A -> B -> C -> A
        if (nodeName == "NodeA") {
            graph.addDependency(nodeC.get(), nodeA.get()); // C -> A
        } else if (nodeName == "NodeB") {
            graph.addDependency(nodeC.get(), nodeB.get()); // C -> B
        } else {
            graph.addDependency(nodeC.get(), nodeA.get()); // Default: C -> A
        }

        // Commit the transaction (this should throw if cycle is detected)
        graph.commitTransaction();

    } catch (const reaction::CycleException& e) {
        // 7. Catch cycle exception if thrown
        cycleDetected = true;
        graph.rollbackTransaction();
