    }, doubleCalc).setName("logger_action");

    // Retrieve names via getName() to verify naming functionality
    const std::string names =
        varA.getName() + "|" + varB.getName() + "|" + sumCalc.getName() + "|" +
        doubleCalc.getName() + "|" + logger.getName();

    return names;
}

