    RecordingNode node1, node2;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.registerNode(&node1);
    graph.registerNode(&node2);

    // 4. Set up initial dependency
    graph.addDependency(&node1, &node2);

    // 5. Save node state for rollback
    graph.saveState();

    // 6. Replace dependencies transactionally
    graph.beginTransaction();
    graph.removeDependency(&node1, &node2);

    // Create a sensor node for the second binding
    reaction::SensorNode sensor2;
    graph.registerNode(&sensor2);
    graph.addDependency(&node1, &sensor2);
    graph.commitTransaction();

    // 7. Trigger notification on second sensor
    sensor2.notifyObservers();

    // 8. Record notification count after second binding
    RollbackObservation result;
    result.notificationsAfterSecondBinding = node1.notificationCount();

    // 9. Execute rollback
    graph.rollbackState();

    // 10. Trigger notification on first sensor (node2 acting as sensor)
    node2.notifyObservers();

    // 11. Record notification count after rollback
    result.notificationsAfterRollback = node1.notificationCount();

    return result;
