#include "test_thread_manager_multithread.h"

namespace test_reaction {

ThreadSafetyStatus test_thread_manager_multithread() {
    // 1. Get thread manager instance
    auto& thread_manager = reaction::concurrency::thread_manager::get_instance();

    // 2. Reset thread manager state
    thread_manager.reset();

    // 3. Register current thread
    thread_manager.register_this_thread();

    // 4. Get thread count and safety status before
    bool safetyBefore = thread_manager.is_thread_safe();
    std::size_t threadCountBefore = thread_manager.get_thread_count();

    // 5. Create and start worker thread
    std::thread worker_thread([&thread_manager]() {
        thread_manager.register_this_thread();
        // Simulate some work
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
        thread_manager.unregister_this_thread();
    });

    // 6. Wait for worker thread
    worker_thread.join();

    // 7. Get thread count and safety status after
    bool safetyAfter = thread_manager.is_thread_safe();
    std::size_t threadCountAfter = thread_manager.get_thread_count();

    // 8. Return thread safety status
    return ThreadSafetyStatus{
        safetyBefore,
        safetyAfter,
        threadCountBefore,
        threadCountAfter
    };
}

}  // namespace test_reaction
