    thread_manager.enableThreadSafety();

    // Create shallow and deep DepthProbeNode instances
    auto shallow_node = std::make_shared<DepthProbeNode>();
    auto deep_node = std::make_shared<DepthProbeNode>();

    // Create NodeWeak from nodes
    reaction::NodeWeak shallow_weak(shallow_node);
    reaction::NodeWeak deep_weak(deep_node);

    // Create BatchCompare instance
    reaction::BatchCompare comparator;

    // Compare initial nodes
    bool initial_comparison = comparator(shallow_weak, deep_weak);

    // Update depths of nodes
    shallow_node->updateDepth(1);
    deep_node->updateDepth(5);

    // Compare shallow before deep
    bool shallow_before_deep = comparator(shallow_weak, deep_weak);

    // Update depth of shallow node again
    shallow_node->updateDepth(10);

    // Compare deep before shallow
    bool deep_before_shallow = comparator(deep_weak, shallow_weak);

    // Create null NodeWeak
    reaction::NodeWeak null_weak;

    // Compare null with shallow
    bool null_comes_first = comparator(null_weak, shallow_weak);

    // Return depth ordering snapshot
    return DepthOrderingSnapshot{
        initial_comparison,
        shallow_before_deep,
        deep_before_shallow,
        null_comes_first
    };
}

}  // namespace test_reaction

