 *         after the main-thread registration, and after the worker-thread registration.
 */
inline ForceRegisterSnapshot test_thread_manager_force_register() {
    using namespace reaction::concurrency;

    // 1. Get thread manager instance
    ThreadManager& manager = ThreadManager::get_instance();

    // 2. Reset thread manager state
    manager.reset();

    // 3. Check thread safety before registration
    bool safety_before = manager.is_thread_safety_enabled();

    // 4. Register main thread
    manager.force_register_thread();

    // 5. Check thread safety after main thread registration
    bool safety_after_main = manager.is_thread_safety_enabled();

    // 6. Create worker thread and register it
    std::atomic<bool> worker_registered{false};
    bool worker_safety_state = false;

    std::thread worker([&manager, &worker_registered, &worker_safety_state]() {
        manager.force_register_thread();
        worker_safety_state = manager.is_thread_safety_enabled();
        worker_registered.store(true, std::memory_order_release);
