    worker.join();

    // Ensure worker registration is visible
    while (!worker_registered.load(std::memory_order_acquire)) {
        std::this_thread::yield();
    }

    // 8. Check thread safety after worker thread registration
    bool safety_after_worker = manager.is_thread_safety_enabled();

    // 9. Return force register snapshot
    return ForceRegisterSnapshot{
